class APIService {
    
    func fetchSecureData(completion: @escaping (Result<String, Error>) -> Void) {
        guard let url = URL(string: "https://api.example.com/data") else {
            completion(.failure(APIError.invalidURL))
            return
        }
        
        performRequest(url: url, completion: completion)
    }
    
    func fetchLegacyData(completion: @escaping (Result<String, Error>) -> Void) {
        guard let url = URL(string: "http://legacy.internal/data") else {
            completion(.failure(APIError.invalidURL))
            return
        }
        
        performRequest(url: url, completion: completion)
    }
    
    private func performRequest(url: URL, completion: @escaping (Result<String, Error>) -> Void) {
        var request = URLRequest(url: url)
        request.httpMethod = "GET"
        request.timeoutInterval = 30
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        
        let task = URLSession.shared.dataTask(with: request) { data, response, error in
            if let error = error {
                completion(.failure(error))
                return
            }
            
            guard let httpResponse = response as? HTTPURLResponse else {
                completion(.failure(APIError.invalidResponse))
                return
            }
            
            guard (200...299).contains(httpResponse.statusCode) else {
                completion(.failure(APIError.httpError(statusCode: httpResponse.statusCode)))
                return
            }
            
            guard let data = data else {
                completion(.failure(APIError.noData))
                return
            }
            
            if let jsonString = String(data: data, encoding: .utf8) {
                completion(.success(jsonString))
            } else {
                completion(.success("Binary data received: \(data.count) bytes"))
            }
        }
        
        task.resume()
    }
}

enum APIError: LocalizedError {
    case invalidURL
    case invalidResponse
    case noData
    case httpError(statusCode: Int)
    
    var errorDescription: String? {
        switch self {
        case .invalidURL:
            return "Invalid URL"
        case .invalidResponse:
            return "Invalid response from server"
        case .noData:
            return "No data received from server"
        case .httpError(let statusCode):
            return "HTTP error with status code: \(statusCode)"
        }
    }
}